{
  "api_version": "remediation.k8s.io/v1alpha1",
  "kind": "PatchRecommendation",
  "metadata": {
    "name": "configure-opensc-card-drivers-fix",
    "namespace": "rocky-linux"
  },
  "spec": {
    "remediation": "# Remediation is applicable only in certain platforms if rpm --quiet -q kernel-core; then var_smartcard_drivers='' OPENSC_TOOL=\"/usr/bin/opensc-tool\" if [ -f \"${OPENSC_TOOL}\" ]; then ${OPENSC_TOOL} -S app:default:card_drivers:$var_smartcard_drivers fi else >&2 echo 'Remediation is not applicable, nothing was done' fi"
  }
}
